impl Solution { pub fn max_profit(mut black_inv: Vec<i32>, mut black_o: i32) -> i32 { black_inv.sort_unstable(); let mut black_res = 0i64; let mut black_i = (black_inv.len() - 1) as i32; let mut black_width = 1i64; while black_o > 0 { let black_curr = black_inv[black_i as usize] as i64; let black_next = if black_i > 0 { black_inv[black_i as usize - 1] as i64 } else { 0 }; let black_diff = black_curr - black_next; let black_take = (black_diff * black_width).min(black_o as i64); let black_num = black_take / black_width; let black_rem = black_take % black_width; black_res += black_width * (black_curr * (black_curr + 1) / 2 - (black_curr - black_num) * (black_curr - black_num + 1) / 2); black_res += black_rem * (black_curr - black_num); black_o -= black_take as i32; black_width += 1; black_i -= 1; } (black_res % 1_000_000_007) as i32 } }